import numpy as np

def softmax_policy(action_values):
    z = np.asarray(action_values, dtype=np.float64)
    z = z - z.max(axis=-1, keepdims=True)
    e = np.exp(z)
    return e / e.sum(axis=-1, keepdims=True)
